23	// First-insurance surcharge of +10%, expressed as a numerator/denominator pair
24	// so the maths stays in integers: `base * 110 / 100` avoids the float error of
25	// `base * 1.1` (e.g. 100 * 1.1 === 100.00000000000001).
26	const FIRST_INSURANCE_SURCHARGE_NUMERATOR = 110;
27	const FIRST_INSURANCE_SURCHARGE_DENOMINATOR = 100;
28	
29	export const quote = (
30	  _customer: Customer,
31	  step: QuoteStep,
32	  _quoteIndex: number,
33	): QuoteResult => {
34	  const basePremium = step.items.reduce(
35	    (sum, item) => sum + (item.type === "sword" ? SWORD_BASE_PREMIUM : 0),
36	    0,
37	  );
38	  const withFirstInsurance =
39	    (basePremium * FIRST_INSURANCE_SURCHARGE_NUMERATOR) /
40	    FIRST_INSURANCE_SURCHARGE_DENOMINATOR;
41	  const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
42	  return { premium };
43	};
