export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  items: Item[];
}

export interface QuoteResult {
  premium: number;
}

// Runes and moonstones are "components" — a distinct pricing tier that shares
// one base premium (and, later, block/alike rules). Naming the shared value
// makes the equality intentional rather than a coincidence two entries happen
// to share.
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
// A "building block" of exactly this many alike components is offered at a
// special block premium instead of the per-component price.
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: COMPONENT_BASE_PREMIUM,
  moonstone: COMPONENT_BASE_PREMIUM,
};
const PROCESSING_FEE = 5;

// First-insurance surcharge of +10%, expressed as a numerator/denominator pair
// so the maths stays in integers: `base * 110 / 100` avoids the float error of
// `base * 1.1` (e.g. 100 * 1.1 === 100.00000000000001).
const FIRST_INSURANCE_SURCHARGE_NUMERATOR = 110;
const FIRST_INSURANCE_SURCHARGE_DENOMINATOR = 100;

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const componentGroupPremium = (count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : count * COMPONENT_BASE_PREMIUM;

const typeGroupPremium = (type: string, count: number): number =>
  COMPONENT_TYPES.has(type)
    ? componentGroupPremium(count)
    : count * (BASE_PREMIUMS[type] ?? 0);

const sumBasePremiums = (items: Item[]): number =>
  [...countByType(items)].reduce(
    (total, [type, count]) => total + typeGroupPremium(type, count),
    0,
  );

export const quote = (
  _customer: Customer,
  step: QuoteStep,
  _quoteIndex: number,
): QuoteResult => {
  const basePremium = sumBasePremiums(step.items);
  const withFirstInsurance =
    (basePremium * FIRST_INSURANCE_SURCHARGE_NUMERATOR) /
    FIRST_INSURANCE_SURCHARGE_DENOMINATOR;
  const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
  return { premium };
};

export const claim = (): unknown => {
  return undefined;
};

