import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office — quote (base premiums)", () => {
  // Simplest case
  it("empty item list → premium 5 (only processing fee)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, { items: [] }, 0).premium).toBe(5);
  });

  // Single main item base premiums (+ fee, no other modifiers; newcomer 0 years would add first-insurance — so use these as base-premium building blocks via the integration examples instead)
  it("single plain sword (base 100) for newcomer → premium 115 (100 + 10% first + 5 fee)", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] },
        0,
      ).premium,
    ).toBe(115);
  });
  it("single plain amulet (base 60) for newcomer → premium 71 (60 + 10% first + 5 fee)", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] },
        0,
      ).premium,
    ).toBe(71);
  });
  it("single plain staff (base 80) for newcomer → premium 93", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { items: [{ type: "staff", material: "wood", enchantment: 2, cursed: false }] },
        0,
      ).premium,
    ).toBe(93);
  });
  it("single plain potion (base 40) for newcomer → premium 49", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { items: [{ type: "potion", material: "liquid", enchantment: 1, cursed: false }] },
        0,
      ).premium,
    ).toBe(49);
  });

  // Components
  it("single rune (base 25) for newcomer → premium 33 (25 + 10% first + 5 fee, rounded up)", () => {
    expect(
      quote({ yearsWithMHPCO: 0 }, { items: [{ type: "rune" }] }, 0).premium,
    ).toBe(33);
  });
  it("single moonstone (base 25) for newcomer → premium 33", () => {
    expect(
      quote({ yearsWithMHPCO: 0 }, { items: [{ type: "moonstone" }] }, 0).premium,
    ).toBe(33);
  });

  // Building block of 3 alike components
  it("2 runes (base 50, no block) for newcomer → premium 60", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { items: [{ type: "rune" }, { type: "rune" }] },
        0,
      ).premium,
    ).toBe(60);
  });
  it("3 runes (block base 60) for newcomer → premium 71", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
        0,
      ).premium,
    ).toBe(71);
  });
  it("4 runes (no block, base 100) for newcomer → premium 115", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        {
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
        0,
      ).premium,
    ).toBe(115);
  });
  it("7 runes (no block, base 175) for newcomer → premium 198 (197.5 rounded up)", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { items: Array.from({ length: 7 }, () => ({ type: "rune" })) },
        0,
      ).premium,
    ).toBe(198);
  });

  // "Alike" components
  it("2 runes + 1 moonstone (no block, base 75) for newcomer → premium 88", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        { items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] },
        0,
      ).premium,
    ).toBe(88);
  });
  it("3 runes + 3 moonstones (two blocks, base 120) for newcomer → premium 137", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        {
          items: [
            ...Array.from({ length: 3 }, () => ({ type: "rune" })),
            ...Array.from({ length: 3 }, () => ({ type: "moonstone" })),
          ],
        },
        0,
      ).premium,
    ).toBe(137);
  });
});

describe("MHPCO Claim Office — quote (premium modifiers)", () => {
  // Item-specific modifiers and policy scope
  it("cursed sword + plain amulet for newcomer → premium 231 (base 160 + curse 50 + 10% first 16 + 5 fee)", () => {
    expect(
      quote(
        { yearsWithMHPCO: 0 },
        {
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: true },
            { type: "amulet", material: "silver", enchantment: 2, cursed: false },
          ],
        },
        0,
      ).premium,
    ).toBe(231);
  });

  // Modifier thresholds
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 5 and cursed → both surcharges apply");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");

  // Rounding
  it.todo("premium calculation yielding 197.5 → final premium 198 (rounded up)");
});

describe("MHPCO Claim Office — quote (integration examples)", () => {
  it.todo("newcomer cursed sword (steel, ench 3), 0 years → premium 165");
  it.todo("long-standing (3 yrs) 2nd contract, cursed sword (steel, ench 7) → premium 160");
});

describe("MHPCO Claim Office — claim (standard reimbursement)", () => {
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400");
  it.todo("rune (value 250), damage 200 → payout 100");
});

describe("MHPCO Claim Office — claim (special clauses)", () => {
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon clause only)");
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-enchantment clause only)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (both clauses; 50% wins)");
  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-enchantment clause applies at exactly 8)");
});

describe("MHPCO Claim Office — claim (deductible per damage event)", () => {
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
  it.todo("two swords, dragon attack damages both → each entry own deductible");
  it.todo("more damage entries of a type than policy covers → claim rejected (error)");
});

describe("MHPCO Claim Office — claim (cap)", () => {
  it.todo("sword cap 2000; claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword cap 2000; two claims 1500 each → first payout 1400 rem 600, second payout 600 rem 0");
});

describe("MHPCO Claim Office — claim (rounding)", () => {
  it.todo("payout calculation yielding 350.5 → final payout 350 (rounded down)");
});

describe("MHPCO Claim Office — errors", () => {
  it.todo("quote with unknown item type → throws/error");
  it.todo("claim references damage item not in policy → throws/error");
  it.todo("claim with negative damage amount → throws/error");
});

