17	  premium: number;
18	}
19	
20	// Runes and moonstones are "components" — a distinct pricing tier that shares
21	// one base premium (and, later, block/alike rules). Naming the shared value
22	// makes the equality intentional rather than a coincidence two entries happen
23	// to share.
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	// A "building block" of exactly this many alike components is offered at a
27	// special block premium instead of the per-component price.
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	
31	const BASE_PREMIUMS: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: COMPONENT_BASE_PREMIUM,
37	  moonstone: COMPONENT_BASE_PREMIUM,
38	};
39	const PROCESSING_FEE = 5;
40	
41	// Surcharges are expressed as integer percentages and applied as
42	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
43	// such as `100 * 1.1 === 100.00000000000001`).
44	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
45	const CURSE_SURCHARGE_PERCENT = 50;
46	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
47	const HIGH_ENCHANTMENT_MIN_LEVEL = 5;
48	const LOYALTY_DISCOUNT_PERCENT = 20;
49	const LOYALTY_MIN_YEARS = 2;
50	
51	const percentOf = (amount: number, percent: number): number =>
52	  (amount * percent) / 100;
53	
54	// A surcharge that applies only when a condition holds, expressed as a
55	// percentage of some base amount (and 0 otherwise).
56	const conditionalPercent = (
57	  applies: boolean,
58	  amount: number,
59	  percent: number,
60	): number => (applies ? percentOf(amount, percent) : 0);
61	
62	// A single item's base premium. BASE_PREMIUMS is the single source of truth
63	// for per-type base prices (components included), so a plain lookup suffices —
64	// block pricing is a group-level concern handled separately in sumBasePremiums.
65	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
66	
67	// Item-specific surcharges, each a percentage of the item's own base premium:
68	// a curse adds 50%, and a highly-enchanted item (level >= 5) adds 30%. They
69	// stack when both apply.
70	const itemSurcharge = (item: Item): number => {
71	  const base = itemBasePremium(item);
72	  const curse = conditionalPercent(
73	    item.cursed ?? false,
74	    base,
75	    CURSE_SURCHARGE_PERCENT,
76	  );
77	  const highEnchantment = conditionalPercent(
78	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MIN_LEVEL,
79	    base,
80	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
81	  );
82	  return curse + highEnchantment;
83	};
84	
85	const sumItemSurcharges = (items: Item[]): number =>
86	  items.reduce((total, item) => total + itemSurcharge(item), 0);
87	
88	const countByType = (items: Item[]): Map<string, number> => {
89	  const counts = new Map<string, number>();
90	  for (const item of items) {
91	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
92	  }
93	  return counts;
94	};
95	
96	const componentGroupPremium = (count: number): number =>
97	  count === COMPONENT_BLOCK_SIZE
98	    ? COMPONENT_BLOCK_PREMIUM
99	    : count * COMPONENT_BASE_PREMIUM;
100	
101	const typeGroupPremium = (type: string, count: number): number =>
102	  COMPONENT_TYPES.has(type)
103	    ? componentGroupPremium(count)
104	    : count * (BASE_PREMIUMS[type] ?? 0);
105	
106	const sumBasePremiums = (items: Item[]): number =>
107	  [...countByType(items)].reduce(
108	    (total, [type, count]) => total + typeGroupPremium(type, count),
109	    0,
110	  );
111	
112	// Policy-wide modifiers scale with the whole policy's base premium.
113	// First-insurance is a surcharge every new policy pays; the loyalty discount
114	// rewards customers at or past the loyalty threshold.
115	const firstInsuranceSurcharge = (policyBase: number): number =>
116	  percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
117	
118	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
119	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
120	    ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
121	    : 0;
122	
123	export const quote = (
124	  customer: Customer,
125	  step: QuoteStep,
126	  _quoteIndex: number,
127	): QuoteResult => {
128	  const policyBase = sumBasePremiums(step.items);
129	  const premium = Math.ceil(
130	    policyBase +
131	      sumItemSurcharges(step.items) +
132	      firstInsuranceSurcharge(policyBase) -
133	      loyaltyDiscount(customer, policyBase) +
134	      PROCESSING_FEE,
135	  );
136	  return { premium };
137	};
138	
139	export const claim = (): unknown => {
140	  return undefined;
141	};

