const CURSE_SURCHARGE_PERCENT = 50;
const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
const HIGH_ENCHANTMENT_MIN_LEVEL = 5;
const LOYALTY_DISCOUNT_PERCENT = 20;
