  const highEnchantment = conditionalPercent(
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MIN_LEVEL,
    base,
    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
  );
  return curse + highEnchantment;
};

