// Reimbursement for one damage before the deductible: standard claims are
// reimbursed in full.
const reimbursement = (damage: Damage): number => damage.amount;

// Payout for one damage: the reimbursement minus the deductible, never below 0.
const damagePayout = (damage: Damage): number =>
  Math.max(0, reimbursement(damage) - DEDUCTIBLE);

export const claim = (
  _policyItems: Item[],
  incident: Incident,
  remainingCap: number,
): ClaimResult => {
  const requested = incident.damages.reduce(
    (total, damage) => total + damagePayout(damage),
    0,
  );
  const payout = Math.floor(Math.min(requested, remainingCap));
  return { payout, remainingCap: remainingCap - payout };
};

