164	  policyBase: number,
165	): number =>
166	  firstInsuranceSurcharge(policyBase) -
167	  loyaltyDiscount(customer, policyBase) -
168	  followUpDiscount(quoteIndex, policyBase);
169	
170	export const quote = (
171	  customer: Customer,
172	  step: QuoteStep,
173	  quoteIndex: number,
174	): QuoteResult => {
175	  const policyBase = sumBasePremiums(step.items);
176	  const premium = Math.ceil(
177	    policyBase +
178	      sumItemSurcharges(step.items) +
179	      policyAdjustments(customer, quoteIndex, policyBase) +
180	      PROCESSING_FEE,
181	  );
182	  return { premium };
183	};
184	
185	// Reimbursement for one damage before the deductible: standard claims are
186	// reimbursed in full.
187	const reimbursement = (damage: Damage): number => damage.amount;
188	
189	// Payout for one damage: the reimbursement minus the deductible, never below 0.
190	const damagePayout = (damage: Damage): number =>
191	  Math.max(0, reimbursement(damage) - DEDUCTIBLE);
192	
193	export const claim = (
194	  _policyItems: Item[],
195	  incident: Incident,
196	  remainingCap: number,
197	): ClaimResult => {
198	  const requested = sumBy(incident.damages, damagePayout);
199	  const payout = Math.floor(Math.min(requested, remainingCap));
200	  return { payout, remainingCap: remainingCap - payout };
201	};

