30	export interface ClaimResult {
31	  payout: number;
32	  remainingCap: number;
33	}
34	
35	// Runes and moonstones are "components" — a distinct pricing tier that shares
36	// one base premium (and, later, block/alike rules). Naming the shared value
37	// makes the equality intentional rather than a coincidence two entries happen
38	// to share.
39	const COMPONENT_BASE_PREMIUM = 25;
40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	// A "building block" of exactly this many alike components is offered at a
42	// special block premium instead of the per-component price.
43	const COMPONENT_BLOCK_SIZE = 3;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	
46	const BASE_PREMIUMS: Record<string, number> = {
47	  sword: 100,
48	  amulet: 60,
49	  staff: 80,
50	  potion: 40,
51	  rune: COMPONENT_BASE_PREMIUM,
52	  moonstone: COMPONENT_BASE_PREMIUM,
53	};
54	const PROCESSING_FEE = 5;
55	
56	// Surcharges are expressed as integer percentages and applied as
57	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
58	// such as `100 * 1.1 === 100.00000000000001`).
59	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
60	const CURSE_SURCHARGE_PERCENT = 50;
61	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
62	const HIGH_ENCHANTMENT_MIN_LEVEL = 5;
63	const LOYALTY_DISCOUNT_PERCENT = 20;
64	const LOYALTY_MIN_YEARS = 2;
65	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
66	const FIRST_CONTRACT_INDEX = 0;
67	const DEDUCTIBLE = 100;
68	const HIGH_ENCHANTMENT_CLAIM_MIN_LEVEL = 8;
69	const HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT = 50;
70	
71	// Sum a numeric measure over a list. Centralises the
72	// `reduce((total, x) => total + f(x), 0)` shape shared by every per-item /
73	// per-damage total in this module, so each caller states only *what* it sums.
74	const sumBy = <T>(items: T[], measure: (item: T) => number): number =>
75	  items.reduce((total, item) => total + measure(item), 0);
76	
77	const percentOf = (amount: number, percent: number): number =>
78	  (amount * percent) / 100;
79	
80	// A surcharge that applies only when a condition holds, expressed as a
81	// percentage of some base amount (and 0 otherwise).
82	const conditionalPercent = (
83	  applies: boolean,
84	  amount: number,
85	  percent: number,
86	): number => (applies ? percentOf(amount, percent) : 0);
87	
88	// The base premium for a given item type, with unknown types priced at 0.
89	// This is the single point that reads BASE_PREMIUMS, so both per-item and
90	// per-group pricing share one definition of "the base price of a type".
91	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
92	
93	// A single item's base premium. Block pricing is a group-level concern handled
94	// separately in sumBasePremiums, so a plain per-type lookup suffices here.
95	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
96	
97	// Item-specific surcharges, each a percentage of the item's own base premium:
98	// a curse adds 50%, and a highly-enchanted item (level >= 5) adds 30%. They
99	// stack when both apply.
100	const itemSurcharge = (item: Item): number => {
101	  const base = itemBasePremium(item);
102	  const curse = conditionalPercent(
103	    item.cursed ?? false,
104	    base,
105	    CURSE_SURCHARGE_PERCENT,
106	  );
107	  const highEnchantment = conditionalPercent(
108	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MIN_LEVEL,
109	    base,
110	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
111	  );
112	  return curse + highEnchantment;
113	};
114	
115	const sumItemSurcharges = (items: Item[]): number =>
116	  sumBy(items, itemSurcharge);
117	
118	const countByType = (items: Item[]): Map<string, number> => {
119	  const counts = new Map<string, number>();
120	  for (const item of items) {
121	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
122	  }
123	  return counts;
124	};
125	
126	const componentGroupPremium = (count: number): number =>
127	  count === COMPONENT_BLOCK_SIZE
128	    ? COMPONENT_BLOCK_PREMIUM
129	    : count * COMPONENT_BASE_PREMIUM;
130	
131	const typeGroupPremium = (type: string, count: number): number =>
132	  COMPONENT_TYPES.has(type)
133	    ? componentGroupPremium(count)
134	    : count * basePremiumForType(type);
135	
136	const sumBasePremiums = (items: Item[]): number =>
137	  sumBy([...countByType(items)], ([type, count]) =>
138	    typeGroupPremium(type, count),
139	  );
140	
141	// Policy-wide modifiers scale with the whole policy's base premium.
142	// First-insurance is a surcharge every new policy pays; the loyalty discount
143	// rewards customers at or past the loyalty threshold.
144	const firstInsuranceSurcharge = (policyBase: number): number =>
145	  percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
146	
147	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
148	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
149	    ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
150	    : 0;
151	
152	// Every contract after the customer's first quote in the scenario is a
153	// follow-up contract and earns a discount.
154	const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
155	  quoteIndex > FIRST_CONTRACT_INDEX
156	    ? percentOf(policyBase, FOLLOWUP_CONTRACT_DISCOUNT_PERCENT)
157	    : 0;
158	
159	// Net signed adjustment that policy-wide modifiers make to the policy base:
160	// the first-insurance surcharge adds, the loyalty and follow-up discounts
161	// subtract. Grouping them keeps the quote formula at "base + item surcharges
162	// + policy-wide adjustments + fee".
163	const policyAdjustments = (
164	  customer: Customer,
165	  quoteIndex: number,
166	  policyBase: number,
167	): number =>
168	  firstInsuranceSurcharge(policyBase) -
169	  loyaltyDiscount(customer, policyBase) -
170	  followUpDiscount(quoteIndex, policyBase);
171	
172	export const quote = (
173	  customer: Customer,
174	  step: QuoteStep,
175	  quoteIndex: number,
176	): QuoteResult => {
177	  const policyBase = sumBasePremiums(step.items);
178	  const premium = Math.ceil(
179	    policyBase +
180	      sumItemSurcharges(step.items) +
181	      policyAdjustments(customer, quoteIndex, policyBase) +
182	      PROCESSING_FEE,
183	  );
184	  return { premium };
185	};
186	
187	// Reimbursement for one damage before the deductible. A highly-enchanted item
188	// (level >= 8) is reimbursed at 50% of the damage; otherwise in full.
189	const reimbursement = (item: Item, damage: Damage): number =>
190	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_MIN_LEVEL
191	    ? percentOf(damage.amount, HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT)
192	    : damage.amount;
193	
194	// Payout for one damage: the reimbursement minus the deductible, never below 0.
195	const damagePayout = (item: Item, damage: Damage): number =>
196	  Math.max(0, reimbursement(item, damage) - DEDUCTIBLE);
197	
198	// The policy item insuring a given damage's type. The non-null assertion
199	// assumes the type is covered; rejecting damages for uncovered types is a
200	// separate validation concern (a later test), and isolating the lookup here
201	// gives that change a single place to act.
202	const itemFor = (policyItems: Item[], damage: Damage): Item =>
203	  policyItems.find((item) => item.type === damage.itemType)!;
204	
205	export const claim = (
206	  policyItems: Item[],
207	  incident: Incident,
208	  remainingCap: number,
209	): ClaimResult => {
210	  const requested = sumBy(incident.damages, (damage) =>
211	    damagePayout(itemFor(policyItems, damage), damage),
212	  );
213	  const payout = Math.floor(Math.min(requested, remainingCap));
214	  return { payout, remainingCap: remainingCap - payout };
215	};

